// ├втАЭтВм├втАЭтВм Documentos de obra (PRL ├втВмтАЭ RD 1627/1997) ├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм
async function getDocumentosObra(request, env) {
  const { empresa_id, isSuperadmin, isEmpresaAdmin, isAdmin, isDesarrollador, obra_id: obraAuth, rol, departamento } = await getAuth(request, env);
  if (!empresa_id) return err('No autorizado', 403);
  const url = new URL(request.url);
  const obra_id = url.searchParams.get('obra_id');
  const tipo = url.searchParams.get('tipo');
  const estado = url.searchParams.get('estado');

  const elaborado_por = url.searchParams.get('elaborado_por');
  let sql = `SELECT * FROM documentos_obra WHERE empresa_id=?`;
  const binds = [empresa_id];
  if (obraAuth && !isSuperadmin && !isEmpresaAdmin && !isAdmin) { sql += ` AND obra_id=?`; binds.push(obraAuth); }
  if (obra_id)      { sql += ` AND obra_id=?`;       binds.push(obra_id); }
  // DEPT-01 (21/07/2026): columna departamento a├▒adida (migraci├│n manual, ver
  // migrate_dept01_construccion.sql). Antes esto era BUG-CARNETS (filtro roto -> 500); ahora
  // filtra de verdad por departamento salvo admins/Seguridad, que ven todos.
  const _isPriv = isSuperadmin || isEmpresaAdmin || isDesarrollador || departamento === 'seguridad';
  if (!_isPriv && departamento) { sql += ` AND (departamento=? OR departamento IS NULL)`; binds.push(departamento); }
  if (tipo)         { sql += ` AND tipo=?`;           binds.push(tipo); }
  if (estado)       { sql += ` AND estado=?`;         binds.push(estado); }
  if (elaborado_por){ sql += ` AND elaborado_por=?`;  binds.push(elaborado_por); }
  sql += ` ORDER BY tipo ASC, created_at DESC`;
  const rows = await env.DB.prepare(sql).bind(...binds).all();
  return json({ ok: true, items: rows.results || [] });
}

