async function handleOCR(request, env) {
  // SEC-09: requiere sesi├Г┬│n v├Г┬бlida ├втВмтАЭ evita consumo de cuota de Cloud Vision sin autenticar
  const xTokOcr = request.headers.get('X-Token');
  if (!xTokOcr) return err('No autorizado', 401);
  const _sOcr = await env.DB.prepare("SELECT id FROM sesiones WHERE token = ? AND (expires_at IS NULL OR expires_at > datetime('now'))").bind(xTokOcr).first().catch(() => null);
  if (!_sOcr) return err('No autorizado', 401);
  if (!env.GOOGLE_CLIENT_EMAIL || !env.GOOGLE_PRIVATE_KEY) {
    return err('Credenciales Google no configuradas', 500);
  }

  const { image, mimeType = 'image/jpeg' } = await request.json();
  if (!image) return err('Se requiere imagen en base64');

  try {
    const token = await getGoogleToken(env, 'https://www.googleapis.com/auth/cloud-vision');

    const res = await fetch('https://vision.googleapis.com/v1/images:annotate', {
      method: 'POST',
      headers: { 'Authorization': `Bearer ${token}`, 'Content-Type': 'application/json' },
      body: JSON.stringify({
        requests: [{
          image: { content: image },
          features: [{ type: 'TEXT_DETECTION', maxResults: 1 }],
          imageContext: { languageHints: ['es', 'en'] },
        }],
      }),
    });

    const data = await res.json();
    if (!res.ok) return json({ error: 'Error Cloud Vision', details: data }, res.status);

    const textoCompleto = data.responses?.[0]?.textAnnotations?.[0]?.description || '';
    if (!textoCompleto) return json({ codigo: 'NO_LEIDO' });

    const UI_WORDS = new Set([
      'PINCELES','CALIBRI','FORMAS','COLORES','COPILOT','CAPAS','RELLENO','FONDO',
      'COPIAR','PEGAR','ARCHIVO','EDITAR','VER','INSERTAR','INICIO','AYUDA',
      'FORMATO','HERRAMIENTAS','VENTANA','IMAGEN','TEXTO','DIBUJAR','SELECCIONAR',
      'SHAPES','COLORS','BRUSHES','LAYERS','FILL','TOOLS','EDIT','FILE','VIEW',
      'CANVAS','ZOOM','UNDO','REDO','COPY','PASTE','CUT','SELECT','CROP',
    ]);

    const lineas = textoCompleto
      .split('\n')
      .map(l => l.trim().toUpperCase().replace(/[^A-Z0-9\-\/]/g, ''))
      .filter(l => l.length >= 3 && !UI_WORDS.has(l));

    const patronBobina = /^[A-Z]{1,4}[-\/]?[0-9]{3,}[A-Z]{0,2}$/;
    const matricula = lineas.find(l => patronBobina.test(l))
      || lineas
          .filter(l => /[A-Z]/.test(l) && /[0-9]/.test(l))
          .sort((a, b) => (b.match(/[0-9]/g) || []).length - (a.match(/[0-9]/g) || []).length)[0]
      || lineas.sort((a, b) => b.length - a.length)[0]
      || 'NO_LEIDO';

    return json({ codigo: matricula, textoCompleto, metodo: 'Cloud Vision' });
  } catch (e) {
    return err(`Error OCR: ${e.message}`, 500);
  }
}

async function handleScan(request, env) {
  // SEC-09: requiere sesi├Г┬│n v├Г┬бlida ├втВмтАЭ evita consumo de cuota de Gemini sin autenticar
  const xTokScan = request.headers.get('X-Token');
  if (!xTokScan) return err('No autorizado', 401);
  const _sScan = await env.DB.prepare("SELECT id FROM sesiones WHERE token = ? AND (expires_at IS NULL OR expires_at > datetime('now'))").bind(xTokScan).first().catch(() => null);
  if (!_sScan) return err('No autorizado', 401);
  const body      = await request.json();
  const imageData = body.image;
  const mimeType  = body.mimeType || 'image/jpeg';
  if (!imageData) return err('Se requiere imagen en base64');

  const prompt = `Eres un lector OCR especializado en matr├Г┬нculas de bobinas de cable el├Г┬йctrico.
Extrae ├Г┼бNICAMENTE el c├Г┬│digo alfanum├Г┬йrico principal de la matr├Г┬нcula/etiqueta visible en la imagen.
El c├Г┬│digo suele ser una combinaci├Г┬│n de letras y n├Г┬║meros (ej: AB1234, C-2891-X, 45872-B).
Responde SOLO con el c├Г┬│digo, sin explicaciones, sin espacios extra, sin puntos al final.
Si no puedes leer ning├Г┬║n c├Г┬│digo, responde: NO_LEIDO`;

  const geminiBody = {
    contents: [{ parts: [
      { inline_data: { mime_type: mimeType, data: imageData } },
      { text: prompt },
    ]}],
    generationConfig: { temperature: 0, maxOutputTokens: 50 },
  };
  const gemResult = await callGemini(env, geminiBody, 'ocr');
  if (gemResult.ok) {
    logAIUsage(env, {
      empresa_id: null,
      proveedor: 'gemini',
      modelo: gemResult.model,
      endpoint: 'ocr',
      input_tokens: gemResult.data.usageMetadata?.promptTokenCount || 0,
      output_tokens: gemResult.data.usageMetadata?.candidatesTokenCount || 0,
    });
    return json({ codigo: gemResult.data.candidates?.[0]?.content?.parts?.[0]?.text?.trim() || 'NO_LEIDO', modelo: gemResult.model });
  }

  // Fallback a Cloud Vision si Gemini est├Г┬б agotado
  if (env.GOOGLE_CLIENT_EMAIL && env.GOOGLE_PRIVATE_KEY) {
    const ocrRequest = new Request('https://dummy/ocr', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ image: imageData, mimeType }),
    });
    const ocrResult = await handleOCR(ocrRequest, env);
    const ocrData   = await ocrResult.json();
    if (ocrData.codigo && ocrData.codigo !== 'NO_LEIDO') {
      return json({ ...ocrData, modelo: 'Cloud Vision (fallback)' });
    }
  }

  return err('Cuota de Gemini agotada. Usa el modo OCR.', 429);
}

// ├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р├Г┬в├втВм┬в├ГтАЪ├В┬Р
