// ├втАЭтВм├втАЭтВм Fases de obra (NEW-30) ├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм
async function devAICostes(request, env) {
  const s = await getAuth(request, env);
  if (!s || !hasRole(s, 'superadmin', 'desarrollador')) return err('Sin permiso', 403);
  try {
    const [total, mesActual, porProveedor, porEndpoint, tendencia, ultimasLlamadas, agenteTotal, agenteMesActual, agentePorProveedor] = await Promise.all([
      env.DB.prepare(`
        SELECT
          ROUND(SUM(coste_usd), 4) as coste_total,
          COUNT(*) as total_llamadas,
          SUM(input_tokens) as tok_in_total,
          SUM(output_tokens) as tok_out_total
        FROM ai_usage
      `).all(),
      env.DB.prepare(`
        SELECT
          ROUND(SUM(coste_usd), 4) as coste_mes,
          COUNT(*) as llamadas_mes
        FROM ai_usage
        WHERE strftime('%Y-%m', created_at) = strftime('%Y-%m', 'now')
      `).all(),
      env.DB.prepare(`
        SELECT
          proveedor,
          ROUND(SUM(coste_usd), 4) as coste,
          COUNT(*) as llamadas,
          SUM(input_tokens) as tok_in,
          SUM(output_tokens) as tok_out
        FROM ai_usage
        GROUP BY proveedor
        ORDER BY coste DESC
      `).all(),
      env.DB.prepare(`
        SELECT
          endpoint,
          proveedor,
          ROUND(SUM(coste_usd), 4) as coste,
          COUNT(*) as llamadas,
          SUM(input_tokens) as tok_in,
          SUM(output_tokens) as tok_out
        FROM ai_usage
        GROUP BY endpoint
        ORDER BY coste DESC
        LIMIT 10
      `).all(),
      env.DB.prepare(`
        SELECT
          strftime('%Y-%m', created_at) as mes,
          ROUND(SUM(coste_usd), 4) as coste,
          COUNT(*) as llamadas
        FROM ai_usage
        GROUP BY mes
        ORDER BY mes DESC
        LIMIT 6
      `).all(),
      env.DB.prepare(`
        SELECT proveedor, modelo, endpoint,
               input_tokens, output_tokens,
               ROUND(coste_usd, 6) as coste_usd,
               created_at
        FROM ai_usage
        ORDER BY created_at DESC
        LIMIT 20
      `).all(),
      // ├втАЭтВм├втАЭтВм Agente NEXUS (alejandra-agente worker, misma BD, tabla alejandra_token_uso) ├втАЭтВм├втАЭтВм
      env.DB.prepare(`
        SELECT
          ROUND(SUM(coste_usd), 4) as coste_total,
          COUNT(*) as total_llamadas,
          SUM(tokens_entrada) as tok_in_total,
          SUM(tokens_salida) as tok_out_total
        FROM alejandra_token_uso
      `).all(),
      env.DB.prepare(`
        SELECT
          ROUND(SUM(coste_usd), 4) as coste_mes,
          COUNT(*) as llamadas_mes
        FROM alejandra_token_uso
        WHERE strftime('%Y-%m', created_at) = strftime('%Y-%m', 'now')
      `).all(),
      env.DB.prepare(`
        SELECT
          proveedor,
          ROUND(SUM(coste_usd), 4) as coste,
          COUNT(*) as llamadas,
          SUM(tokens_entrada) as tok_in,
          SUM(tokens_salida) as tok_out
        FROM alejandra_token_uso
        GROUP BY proveedor
        ORDER BY coste DESC
      `).all(),
    ]);

    const agente = {
      total: agenteTotal.results[0] || {},
      mesActual: agenteMesActual.results[0] || {},
      porProveedor: agentePorProveedor.results || []
    };

    // Total unificado = Alejandra Office (ai_usage) + Agente NEXUS (alejandra_token_uso).
    // Solo lectura: no se toca el esquema ni el path de escritura de ninguno de los
    // dos workers (cada uno sigue registrando en su propia tabla como hasta ahora).
    const unificado = {
      coste_total: Math.round(((total.results[0]?.coste_total || 0) + (agente.total.coste_total || 0)) * 10000) / 10000,
      total_llamadas: (total.results[0]?.total_llamadas || 0) + (agente.total.total_llamadas || 0),
      coste_mes: Math.round(((mesActual.results[0]?.coste_mes || 0) + (agente.mesActual.coste_mes || 0)) * 10000) / 10000,
      llamadas_mes: (mesActual.results[0]?.llamadas_mes || 0) + (agente.mesActual.llamadas_mes || 0)
    };

    return json({
      ok: true,
      total: total.results[0] || {},
      mesActual: mesActual.results[0] || {},
      porProveedor: porProveedor.results || [],
      porEndpoint: porEndpoint.results || [],
      tendencia: tendencia.results || [],
      ultimasLlamadas: ultimasLlamadas.results || [],
      agente,
      unificado
    });
  } catch (e) {
    return json({ ok: false, error: String(e.message) }, { status: 500 });
  }
}

async function ensureFasesObraTable(env) {
  await env.DB.prepare(`
    CREATE TABLE IF NOT EXISTS fases_obra (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      obra_id INTEGER NOT NULL,
      empresa_id INTEGER NOT NULL,
      nombre TEXT NOT NULL,
      descripcion TEXT,
      fecha_inicio_plan TEXT,
      fecha_fin_plan TEXT,
      fecha_inicio_real TEXT,
      fecha_fin_real TEXT,
      porcentaje INTEGER DEFAULT 0,
      estado TEXT DEFAULT 'pendiente',
      responsable TEXT,
      orden INTEGER DEFAULT 0,
      created_at DATETIME DEFAULT CURRENT_TIMESTAMP
    )
  `).run().catch(()=>{});
}

async function getFasesObra(request, env) {
  const auth = await getAuth(request, env);
  if (!auth.empresa_id) return err('No autorizado', 403);
  await ensureFasesObraTable(env);
  const url = new URL(request.url);
  const obra_id = url.searchParams.get('obra_id') ? parseInt(url.searchParams.get('obra_id')) : auth.obra_id;
  if (!obra_id) return json([]);
  const { results } = await env.DB.prepare(
    `SELECT * FROM fases_obra WHERE empresa_id=? AND obra_id=? ORDER BY orden ASC, id ASC`
  ).bind(auth.empresa_id, obra_id).all();
  return json(results || []);
}

async function crearFaseObra(request, env) {
  const auth = await getAuth(request, env);
  if (!auth.empresa_id) return err('No autorizado', 403);
  if (!auth.isEncargado && !auth.isEmpresaAdmin && !auth.isSuperadmin) return err('Sin permisos', 403);
  await ensureFasesObraTable(env);
  const b = await request.json().catch(()=>({}));
  const obra_id = b.obra_id || auth.obra_id;
  if (!obra_id || !b.nombre?.trim()) return err('Faltan datos obligatorios', 400);
  // Calcular siguiente orden
  const maxOrden = await env.DB.prepare(
    `SELECT COALESCE(MAX(orden),0) as m FROM fases_obra WHERE empresa_id=? AND obra_id=?`
  ).bind(auth.empresa_id, obra_id).first();
  const r = await env.DB.prepare(`
    INSERT INTO fases_obra (obra_id, empresa_id, nombre, descripcion, fecha_inicio_plan, fecha_fin_plan, responsable, orden)
    VALUES (?,?,?,?,?,?,?,?)
  `).bind(obra_id, auth.empresa_id, b.nombre.trim(), b.descripcion||null, b.fecha_inicio_plan||null, b.fecha_fin_plan||null, b.responsable||null, (maxOrden?.m||0)+1).run();
  return json({ ok: true, id: r.meta?.last_row_id });
}

async function actualizarFaseObra(id, request, env) {
  const auth = await getAuth(request, env);
  if (!auth.empresa_id) return err('No autorizado', 403);
  const b = await request.json().catch(()=>({}));
  const campos = [];
  const vals = [];
  if (b.nombre !== undefined)          { campos.push('nombre=?');           vals.push(b.nombre); }
  if (b.descripcion !== undefined)     { campos.push('descripcion=?');      vals.push(b.descripcion); }
  if (b.fecha_inicio_plan !== undefined){ campos.push('fecha_inicio_plan=?'); vals.push(b.fecha_inicio_plan); }
  if (b.fecha_fin_plan !== undefined)  { campos.push('fecha_fin_plan=?');   vals.push(b.fecha_fin_plan); }
  if (b.fecha_inicio_real !== undefined){ campos.push('fecha_inicio_real=?'); vals.push(b.fecha_inicio_real); }
  if (b.fecha_fin_real !== undefined)  { campos.push('fecha_fin_real=?');   vals.push(b.fecha_fin_real); }
  if (b.porcentaje !== undefined)      { campos.push('porcentaje=?');       vals.push(Math.max(0,Math.min(100,parseInt(b.porcentaje)||0))); }
  if (b.estado !== undefined)          { campos.push('estado=?');           vals.push(b.estado); }
  if (b.responsable !== undefined)     { campos.push('responsable=?');      vals.push(b.responsable); }
  if (b.orden !== undefined)           { campos.push('orden=?');            vals.push(parseInt(b.orden)||0); }
  if (!campos.length) return err('Nada que actualizar', 400);
  vals.push(id, auth.empresa_id);
  await env.DB.prepare(`UPDATE fases_obra SET ${campos.join(',')} WHERE id=? AND empresa_id=?`).bind(...vals).run();
  return json({ ok: true });
}

