// RFIs ├втВмтАЭ CONSULTAS T├ГтА░CNICAS (NEW-34)
// Tabla: rfis(id, obra_id, empresa_id, numero TEXT, titulo, categoria, descripcion,
//             estado, prioridad, creado_por, asignado_a, respuesta, respondido_por,
