async function ensurePunchListTable(env) {
  await env.DB.prepare(`CREATE TABLE IF NOT EXISTS punch_list (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    empresa_id INTEGER NOT NULL,
    obra_id INTEGER,
    numero TEXT,
    descripcion TEXT NOT NULL,
    categoria TEXT DEFAULT 'acabados',
    ubicacion TEXT,
    responsable TEXT,
    prioridad TEXT DEFAULT 'media',
    estado TEXT DEFAULT 'abierto',
    fecha_limite TEXT,
    fecha_cierre TEXT,
    notas_resolucion TEXT,
    foto_key TEXT,
    creado_por TEXT,
    created_at TEXT DEFAULT (datetime('now'))
  )`).run();
  await env.DB.prepare(`ALTER TABLE punch_list ADD COLUMN departamento TEXT`).run().catch(()=>{}); // DEPT-01 (21/07/2026)
}
async function getPunchList(request, env) {
  const auth = await getAuth(request, env);
  if (!auth?.empresa_id) return err('No autorizado', 403);
  await ensurePunchListTable(env);
  const u = new URL(request.url);
  const obraId   = u.searchParams.get('obra_id');
  const estado   = u.searchParams.get('estado');
  const categoria= u.searchParams.get('categoria');
  let sql = `SELECT p.*, ob.nombre as obra_nombre FROM punch_list p
    LEFT JOIN obras ob ON ob.id=p.obra_id
    WHERE p.empresa_id=?`;
  const params = [auth.empresa_id];
  if (obraId)    { sql += ' AND p.obra_id=?';    params.push(obraId); }
  if (estado)    { sql += ' AND p.estado=?';     params.push(estado); }
  if (categoria) { sql += ' AND p.categoria=?';  params.push(categoria); }
  if (!isDeptPrivileged(auth) && auth.departamento) { sql += ' AND (p.departamento=? OR p.departamento IS NULL)'; params.push(auth.departamento); }
  sql += ' ORDER BY p.created_at DESC';
  const hoy = new Date().toISOString().slice(0,10);
  const { results } = await env.DB.prepare(sql).bind(...params).all();
  return json({ items: (results||[]).map(p => ({
    ...p,
    vencido: p.fecha_limite && p.estado !== 'cerrado' && p.fecha_limite < hoy
  }))});
}
async function crearPunchItem(request, env) {
  const auth = await getAuth(request, env);
  if (!auth?.empresa_id) return err('No autorizado', 403);
  await ensurePunchListTable(env);
  const b = await request.json();
  if (!b.descripcion) return err('descripcion requerida', 400);
  // Auto-n├Г┬║mero: PL-YYYY-NNNN
  const year = new Date().getFullYear();
  const { results: last } = await env.DB.prepare(
    `SELECT numero FROM punch_list WHERE empresa_id=? AND numero LIKE 'PL-${year}-%' ORDER BY id DESC LIMIT 1`
  ).bind(auth.empresa_id).all();
  let seq = 1;
  if (last?.[0]?.numero) { const m = last[0].numero.match(/(\d+)$/); if (m) seq = parseInt(m[1]) + 1; }
  const numero = `PL-${year}-${String(seq).padStart(4,'0')}`;
  const { meta } = await env.DB.prepare(
    `INSERT INTO punch_list (empresa_id,obra_id,numero,descripcion,categoria,ubicacion,responsable,prioridad,estado,fecha_limite,notas_resolucion,foto_key,creado_por,departamento)
     VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?)`
  ).bind(
    auth.empresa_id, b.obra_id||null, numero, b.descripcion,
    b.categoria||'acabados', b.ubicacion||null, b.responsable||null,
    b.prioridad||'media', b.estado||'abierto', b.fecha_limite||null,
    b.notas_resolucion||null, b.foto_key||null, auth.nombre||auth.email||null,
    auth.departamento || null // DEPT-01
  ).run();
  return json({ ok: true, id: meta.last_row_id, numero });
}
async function actualizarPunchItem(id, request, env) {
  const auth = await getAuth(request, env);
  if (!auth?.empresa_id) return err('No autorizado', 403);
  await ensurePunchListTable(env);
  const b = await request.json();
  const fechaCierre = b.estado === 'cerrado' ? (b.fecha_cierre || new Date().toISOString().slice(0,10)) : null;
  const params = [
    b.descripcion||null, b.categoria||null, b.ubicacion||null, b.responsable||null,
    b.prioridad||null, b.estado||null, b.fecha_limite||null, fechaCierre,
    b.notas_resolucion||null, b.foto_key||null, id, auth.empresa_id
  ];
  let deptGuard = '';
  if (!isDeptPrivileged(auth) && auth.departamento) { deptGuard = ` AND (departamento=? OR departamento IS NULL)`; params.push(auth.departamento); }
  await env.DB.prepare(
    `UPDATE punch_list SET descripcion=COALESCE(?,descripcion), categoria=COALESCE(?,categoria),
     ubicacion=COALESCE(?,ubicacion), responsable=COALESCE(?,responsable),
     prioridad=COALESCE(?,prioridad), estado=COALESCE(?,estado),
     fecha_limite=COALESCE(?,fecha_limite), fecha_cierre=?,
     notas_resolucion=COALESCE(?,notas_resolucion), foto_key=COALESCE(?,foto_key)
     WHERE id=? AND empresa_id=?${deptGuard}`
  ).bind(...params).run();
  return json({ ok: true });
}
async function eliminarPunchItem(id, request, env) {
  const auth = await getAuth(request, env);
  if (!auth?.empresa_id) return err('No autorizado', 403);
  const params = [id, auth.empresa_id];
  let deptGuard = '';
  if (!isDeptPrivileged(auth) && auth.departamento) { deptGuard = ` AND (departamento=? OR departamento IS NULL)`; params.push(auth.departamento); }
  await env.DB.prepare(`DELETE FROM punch_list WHERE id=? AND empresa_id=?${deptGuard}`).bind(...params).run();
  return json({ ok: true });
}

// ├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р
//  NEW-45 ├втВмтАЭ CONTROL DE COSTES DE OBRA
// ├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р
async function ensureCostesObraTable(env) {
  await env.DB.prepare(`CREATE TABLE IF NOT EXISTS costes_obra (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    empresa_id INTEGER NOT NULL,
    obra_id INTEGER,
    fase_id INTEGER,
    concepto TEXT NOT NULL,
    tipo TEXT DEFAULT 'otros',
    importe REAL NOT NULL DEFAULT 0,
    fecha TEXT,
    proveedor TEXT,
    factura_ref TEXT,
    notas TEXT,
    creado_por TEXT,
    created_at TEXT DEFAULT (datetime('now'))
  )`).run();
}
async function getCostesObra(request, env) {
  const auth = await getAuth(request, env);
  if (!auth?.empresa_id) return err('No autorizado', 403);
  await ensureCostesObraTable(env);
  const u = new URL(request.url);
  const obraId = u.searchParams.get('obra_id');
  const tipo   = u.searchParams.get('tipo');
  const faseId = u.searchParams.get('fase_id');
  let sql = `SELECT c.*, ob.nombre as obra_nombre, f.nombre as fase_nombre
    FROM costes_obra c
    LEFT JOIN obras ob ON ob.id=c.obra_id
    LEFT JOIN fases_obra f ON f.id=c.fase_id
    WHERE c.empresa_id=?`;
  const params = [auth.empresa_id];
  if (obraId) { sql += ' AND c.obra_id=?'; params.push(obraId); }
  if (tipo)   { sql += ' AND c.tipo=?';    params.push(tipo); }
  if (faseId) { sql += ' AND c.fase_id=?'; params.push(faseId); }
  sql += ' ORDER BY c.fecha DESC, c.created_at DESC';
  const { results } = await env.DB.prepare(sql).bind(...params).all();

  // Resumen por fase (si hay obra_id)
  let resumenFases = [];
  if (obraId) {
    // Presupuesto por fase
    const { results: fases } = await env.DB.prepare(
      `SELECT f.id, f.nombre, f.presupuesto, f.coste_real,
       COALESCE(SUM(c.importe),0) as coste_registrado
       FROM fases_obra f
       LEFT JOIN costes_obra c ON c.fase_id=f.id AND c.empresa_id=?
       WHERE f.obra_id=? AND f.empresa_id=?
       GROUP BY f.id`
    ).bind(auth.empresa_id, obraId, auth.empresa_id).all();
    resumenFases = (fases||[]).map(f => ({
      ...f,
      variacion: (f.presupuesto||0) - (f.coste_registrado||0),
      pct_ejecutado: f.presupuesto ? Math.round(((f.coste_registrado||0) / f.presupuesto) * 100) : 0
    }));
  }

  // Totales globales para la obra
  const totalPresup = resumenFases.reduce((s,f) => s + (f.presupuesto||0), 0);
  const totalReal   = resumenFases.reduce((s,f) => s + (f.coste_registrado||0), 0);

  return json({
    costes: results||[],
    resumen_fases: resumenFases,
    totales: { presupuesto: totalPresup, coste_real: totalReal, variacion: totalPresup - totalReal }
  });
}
async function crearCosteObra(request, env) {
  const auth = await getAuth(request, env);
  if (!auth?.empresa_id) return err('No autorizado', 403);
  const roles = ['superadmin','empresa_admin','encargado','jefe_de_obra','oficina'];
  if (!roles.includes(auth.rol)) return err('Sin permisos', 403);
  await ensureCostesObraTable(env);
  const b = await request.json();
  if (!b.concepto || b.importe == null) return err('concepto e importe requeridos', 400);
  const { meta } = await env.DB.prepare(
    `INSERT INTO costes_obra (empresa_id,obra_id,fase_id,concepto,tipo,importe,fecha,proveedor,factura_ref,notas,creado_por)
     VALUES (?,?,?,?,?,?,?,?,?,?,?)`
  ).bind(
    auth.empresa_id, b.obra_id||null, b.fase_id||null, b.concepto,
    b.tipo||'otros', parseFloat(b.importe)||0,
    b.fecha || new Date().toISOString().slice(0,10),
    b.proveedor||null, b.factura_ref||null, b.notas||null,
    auth.nombre||auth.email||null
  ).run();
  return json({ ok: true, id: meta.last_row_id });
}
async function actualizarCosteObra(id, request, env) {
  const auth = await getAuth(request, env);
  if (!auth?.empresa_id) return err('No autorizado', 403);
  const b = await request.json();
  await env.DB.prepare(
    `UPDATE costes_obra SET concepto=COALESCE(?,concepto), tipo=COALESCE(?,tipo),
     importe=COALESCE(?,importe), fecha=COALESCE(?,fecha), fase_id=COALESCE(?,fase_id),
     proveedor=COALESCE(?,proveedor), factura_ref=COALESCE(?,factura_ref), notas=COALESCE(?,notas)
     WHERE id=? AND empresa_id=?`
  ).bind(
    b.concepto||null, b.tipo||null, b.importe!=null?parseFloat(b.importe):null,
    b.fecha||null, b.fase_id||null, b.proveedor||null, b.factura_ref||null,
    b.notas||null, id, auth.empresa_id
  ).run();
  return json({ ok: true });
}
async function eliminarCosteObra(id, request, env) {
  const auth = await getAuth(request, env);
  if (!auth?.empresa_id) return err('No autorizado', 403);
  await env.DB.prepare(`DELETE FROM costes_obra WHERE id=? AND empresa_id=?`).bind(id, auth.empresa_id).run();
  return json({ ok: true });
}

