async function ensureContactosObraTable(env) {
  await env.DB.prepare(`CREATE TABLE IF NOT EXISTS contactos_obra (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    empresa_id INTEGER,
    obra_id INTEGER,
    nombre TEXT NOT NULL,
    rol TEXT,
    empresa TEXT,
    email TEXT,
    telefono TEXT,
    movil TEXT,
    notas TEXT,
    activo INTEGER DEFAULT 1,
    created_at TEXT DEFAULT (datetime('now'))
  )`).run();
}
async function getContactosObra(request, env) {
  const auth = await getAuth(request, env);
  if (!auth?.empresa_id) return err('No autorizado', 403);
  await ensureContactosObraTable(env);
  const url = new URL(request.url);
  const obraId = url.searchParams.get('obra_id');
  const rol    = url.searchParams.get('rol');
  let q = `SELECT * FROM contactos_obra WHERE empresa_id=? AND activo=1`;
  const params = [auth.empresa_id];
  if (obraId) { q += ` AND obra_id=?`; params.push(parseInt(obraId)); }
  if (rol)    { q += ` AND rol=?`;     params.push(rol); }
  q += ` ORDER BY rol, nombre`;
  const { results } = await env.DB.prepare(q).bind(...params).all();
  return json({ contactos: results });
}
async function crearContactoObra(request, env) {
  const auth = await getAuth(request, env);
  if (!auth?.empresa_id) return err('No autorizado', 403);
  await ensureContactosObraTable(env);
  const b = await request.json();
  if (!b.nombre) return err('nombre requerido', 400);
  const r = await env.DB.prepare(`
    INSERT INTO contactos_obra (empresa_id, obra_id, nombre, rol, empresa, email, telefono, movil, notas, activo)
    VALUES (?,?,?,?,?,?,?,?,?,1)
  `).bind(auth.empresa_id, b.obra_id||null, b.nombre, b.rol||null, b.empresa||null,
          b.email||null, b.telefono||null, b.movil||null, b.notas||null).run();
  return json({ ok: true, id: r.meta?.last_row_id });
}
async function actualizarContactoObra(id, request, env) {
  const auth = await getAuth(request, env);
  if (!auth?.empresa_id) return err('No autorizado', 403);
  const b = await request.json();
  await env.DB.prepare(`
    UPDATE contactos_obra SET nombre=?, rol=?, empresa=?, email=?, telefono=?, movil=?, notas=?, obra_id=?
    WHERE id=? AND empresa_id=?
  `).bind(b.nombre||null, b.rol||null, b.empresa||null, b.email||null,
          b.telefono||null, b.movil||null, b.notas||null, b.obra_id||null,
          id, auth.empresa_id).run();
  return json({ ok: true });
}
async function eliminarContactoObra(id, request, env) {
  const auth = await getAuth(request, env);
  if (!auth?.empresa_id) return err('No autorizado', 403);
  // Soft delete
  await env.DB.prepare(`UPDATE contactos_obra SET activo=0 WHERE id=? AND empresa_id=?`).bind(id, auth.empresa_id).run();
  return json({ ok: true });
}

// ├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р
//  NEW-47 ├втВмтАЭ GESTION DE CONTRATOS DE OBRA
// ├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р
async function ensureContratosObraTable(env) {
  await env.DB.prepare(`CREATE TABLE IF NOT EXISTS contratos_obra (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    empresa_id INTEGER,
    obra_id INTEGER,
    numero TEXT,
    tipo TEXT DEFAULT 'subcontrata',
    titulo TEXT NOT NULL,
    contratista TEXT,
    contacto_id INTEGER,
    importe_original REAL DEFAULT 0,
    importe_actual REAL DEFAULT 0,
    estado TEXT DEFAULT 'borrador',
    fecha_firma TEXT,
    fecha_inicio TEXT,
    fecha_fin TEXT,
    descripcion TEXT,
    notas TEXT,
    created_at TEXT DEFAULT (datetime('now')),
    updated_at TEXT DEFAULT (datetime('now'))
  )`).run();
  // Tabla de ordenes de modificacion de contrato (amendments)
  await env.DB.prepare(`CREATE TABLE IF NOT EXISTS contratos_amendments (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    empresa_id INTEGER,
    contrato_id INTEGER,
    numero TEXT,
    descripcion TEXT,
    importe REAL DEFAULT 0,
    estado TEXT DEFAULT 'pendiente',
    fecha TEXT,
    created_at TEXT DEFAULT (datetime('now'))
  )`).run();
}
async function getContratosObra(request, env) {
  const auth = await getAuth(request, env);
  if (!auth?.empresa_id) return err('No autorizado', 403);
  await ensureContratosObraTable(env);
  const url = new URL(request.url);
  const obraId = url.searchParams.get('obra_id');
  const tipo   = url.searchParams.get('tipo');
  let q = `SELECT c.*, (SELECT COALESCE(SUM(a.importe),0) FROM contratos_amendments a WHERE a.contrato_id=c.id AND a.estado='aprobado') as total_amendments
            FROM contratos_obra c WHERE c.empresa_id=?`;
  const params = [auth.empresa_id];
  if (obraId) { q += ` AND c.obra_id=?`; params.push(parseInt(obraId)); }
  if (tipo)   { q += ` AND c.tipo=?`;    params.push(tipo); }
  q += ` ORDER BY c.created_at DESC`;
  const { results } = await env.DB.prepare(q).bind(...params).all();
  // Totales
  const totalOriginal = results.reduce((s,c)=>s+(c.importe_original||0),0);
  const totalActual   = results.reduce((s,c)=>s+(c.importe_actual||0),0);
  return json({ contratos: results, total_original: totalOriginal, total_actual: totalActual });
}
async function crearContratoObra(request, env) {
  const auth = await getAuth(request, env);
  if (!auth?.empresa_id) return err('No autorizado', 403);
  await ensureContratosObraTable(env);
  const b = await request.json();
  if (!b.titulo) return err('titulo requerido', 400);
  // Auto-numero: CONT-YYYY-NNNN
  const year = new Date().getFullYear();
  const { results: cntR } = await env.DB.prepare(
    `SELECT COUNT(*)+1 as n FROM contratos_obra WHERE empresa_id=? AND substr(numero,6,4)=?`
  ).bind(auth.empresa_id, String(year)).all();
  const num = `CONT-${year}-${String(cntR[0]?.n||1).padStart(4,'0')}`;
  const r = await env.DB.prepare(`
    INSERT INTO contratos_obra (empresa_id, obra_id, numero, tipo, titulo, contratista, contacto_id,
      importe_original, importe_actual, estado, fecha_firma, fecha_inicio, fecha_fin, descripcion, notas)
    VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)
  `).bind(auth.empresa_id, b.obra_id||null, num, b.tipo||'subcontrata', b.titulo,
          b.contratista||null, b.contacto_id||null,
          b.importe_original||0, b.importe_original||0,
          b.estado||'borrador', b.fecha_firma||null, b.fecha_inicio||null, b.fecha_fin||null,
          b.descripcion||null, b.notas||null).run();
  return json({ ok: true, id: r.meta?.last_row_id, numero: num });
}
async function actualizarContratoObra(id, request, env) {
  const auth = await getAuth(request, env);
  if (!auth?.empresa_id) return err('No autorizado', 403);
  const b = await request.json();
  // Recalc importe_actual = original + amendments aprobados
  const { results: ams } = await env.DB.prepare(
    `SELECT COALESCE(SUM(importe),0) as tot FROM contratos_amendments WHERE contrato_id=? AND estado='aprobado'`
  ).bind(id).all();
  const importeActual = (b.importe_original||0) + (ams[0]?.tot||0);
  await env.DB.prepare(`
    UPDATE contratos_obra SET tipo=?, titulo=?, contratista=?, contacto_id=?, importe_original=?, importe_actual=?,
      estado=?, fecha_firma=?, fecha_inicio=?, fecha_fin=?, descripcion=?, notas=?, updated_at=datetime('now')
    WHERE id=? AND empresa_id=?
  `).bind(b.tipo||null, b.titulo||null, b.contratista||null, b.contacto_id||null,
          b.importe_original||0, importeActual,
          b.estado||null, b.fecha_firma||null, b.fecha_inicio||null, b.fecha_fin||null,
          b.descripcion||null, b.notas||null, id, auth.empresa_id).run();
  return json({ ok: true });
}
async function eliminarContratoObra(id, request, env) {
  const auth = await getAuth(request, env);
  if (!auth?.empresa_id) return err('No autorizado', 403);
  await env.DB.prepare(`DELETE FROM contratos_obra WHERE id=? AND empresa_id=?`).bind(id, auth.empresa_id).run();
  await env.DB.prepare(`DELETE FROM contratos_amendments WHERE contrato_id=?`).bind(id).run();
  return json({ ok: true });
}

// ├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р
//  NEW-48 ├втВмтАЭ SUBMITTAL LOG / APROBACIONES DE MATERIALES
// ├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р
async function ensureSubmittalsTable(env) {
  await env.DB.prepare(`CREATE TABLE IF NOT EXISTS submittals (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    empresa_id INTEGER,
    obra_id INTEGER,
    numero TEXT,
    tipo TEXT DEFAULT 'material',
    titulo TEXT NOT NULL,
    descripcion TEXT,
    especificacion TEXT,
    fabricante TEXT,
    modelo TEXT,
    estado TEXT DEFAULT 'pendiente',
    prioridad TEXT DEFAULT 'normal',
    responsable TEXT,
    revisor TEXT,
    revision TEXT DEFAULT 'A',
    fecha_envio TEXT,
    fecha_limite TEXT,
    fecha_respuesta TEXT,
    notas TEXT,
    notas_revision TEXT,
    created_at TEXT DEFAULT (datetime('now')),
    updated_at TEXT DEFAULT (datetime('now'))
  )`).run();
}
async function getSubmittals(request, env) {
  const auth = await getAuth(request, env);
  if (!auth?.empresa_id) return err('No autorizado', 403);
  await ensureSubmittalsTable(env);
  const url = new URL(request.url);
  const obraId = url.searchParams.get('obra_id');
  const estado = url.searchParams.get('estado');
  const tipo   = url.searchParams.get('tipo');
  let q = `SELECT * FROM submittals WHERE empresa_id=?`;
  const params = [auth.empresa_id];
  if (obraId) { q += ` AND obra_id=?`;   params.push(parseInt(obraId)); }
  if (estado) { q += ` AND estado=?`;    params.push(estado); }
  if (tipo)   { q += ` AND tipo=?`;      params.push(tipo); }
  q += ` ORDER BY created_at DESC`;
  const { results } = await env.DB.prepare(q).bind(...params).all();
  const hoy = new Date().toISOString().slice(0,10);
  const items = results.map(s => ({
    ...s,
    vencido: s.estado !== 'aprobado' && s.estado !== 'cerrado' && s.fecha_limite && s.fecha_limite < hoy
  }));
  const pendientes  = items.filter(s=>s.estado==='pendiente').length;
  const en_revision = items.filter(s=>s.estado==='en_revision').length;
  const aprobados   = items.filter(s=>s.estado==='aprobado').length;
  const rechazados  = items.filter(s=>s.estado==='rechazado').length;
  const vencidos    = items.filter(s=>s.vencido).length;
  return json({ submittals: items, pendientes, en_revision, aprobados, rechazados, vencidos });
}
async function crearSubmittal(request, env) {
  const auth = await getAuth(request, env);
  if (!auth?.empresa_id) return err('No autorizado', 403);
  await ensureSubmittalsTable(env);
  const b = await request.json();
  if (!b.titulo) return err('titulo requerido', 400);
  const year = new Date().getFullYear();
  const { results: cntR } = await env.DB.prepare(
    `SELECT COUNT(*)+1 as n FROM submittals WHERE empresa_id=? AND substr(numero,5,4)=?`
  ).bind(auth.empresa_id, String(year)).all();
  const num = `SUB-${year}-${String(cntR[0]?.n||1).padStart(4,'0')}`;
  const r = await env.DB.prepare(`
    INSERT INTO submittals (empresa_id, obra_id, numero, tipo, titulo, descripcion, especificacion,
      fabricante, modelo, estado, prioridad, responsable, revisor, revision, fecha_envio, fecha_limite, notas)
    VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)
  `).bind(auth.empresa_id, b.obra_id||null, num, b.tipo||'material', b.titulo,
          b.descripcion||null, b.especificacion||null, b.fabricante||null, b.modelo||null,
          b.estado||'pendiente', b.prioridad||'normal', b.responsable||auth.nombre||null,
          b.revisor||null, b.revision||'A', b.fecha_envio||null, b.fecha_limite||null, b.notas||null).run();
  return json({ ok: true, id: r.meta?.last_row_id, numero: num });
}
async function actualizarSubmittal(id, request, env) {
  const auth = await getAuth(request, env);
  if (!auth?.empresa_id) return err('No autorizado', 403);
  const b = await request.json();
  const fechaRespuesta = (b.estado==='aprobado'||b.estado==='rechazado'||b.estado==='aprobado_con_notas')
    ? (b.fecha_respuesta || new Date().toISOString().slice(0,10)) : b.fecha_respuesta||null;
  await env.DB.prepare(`
    UPDATE submittals SET tipo=?, titulo=?, descripcion=?, especificacion=?, fabricante=?, modelo=?,
      estado=?, prioridad=?, responsable=?, revisor=?, revision=?, fecha_envio=?, fecha_limite=?,
      fecha_respuesta=?, notas=?, notas_revision=?, updated_at=datetime('now')
    WHERE id=? AND empresa_id=?
  `).bind(b.tipo||null, b.titulo||null, b.descripcion||null, b.especificacion||null,
          b.fabricante||null, b.modelo||null, b.estado||null, b.prioridad||null,
          b.responsable||null, b.revisor||null, b.revision||null,
          b.fecha_envio||null, b.fecha_limite||null, fechaRespuesta, b.notas||null,
          b.notas_revision||null, id, auth.empresa_id).run();
  return json({ ok: true });
}
async function eliminarSubmittal(id, request, env) {
  const auth = await getAuth(request, env);
  if (!auth?.empresa_id) return err('No autorizado', 403);
  await env.DB.prepare(`DELETE FROM submittals WHERE id=? AND empresa_id=?`).bind(id, auth.empresa_id).run();
  return json({ ok: true });
}

// (NEW-49 actas-reunion functions removed ├втВмтАЭ already implemented in NEW-36 above)

// ├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р
//  NEW-51 ├втВмтАЭ AN├Г┬БLISIS FINANCIERO POR OBRA (Financial Dashboard)
// ├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р
async function getFinancieroObra(obraId, request, env) {
  const auth = await getAuth(request, env);
  if (!auth?.empresa_id) return err('No autorizado', 403);

  const empId = auth.empresa_id;

  // ├втАЭтВм├втАЭтВм Fetch en paralelo ├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм
  const [
    obraR, presupuestoR, fasesPR, costesR, contratosTotR,
    costesMesR, costestipoR, contratosTipoR, hitosR
  ] = await Promise.all([
    // Datos de la obra
    env.DB.prepare(`SELECT id, nombre, codigo, estado, fecha_inicio, fecha_fin_prevista, avance_porcentaje
                    FROM obras WHERE id=? AND empresa_id=?`)
      .bind(obraId, empId).first(),
    // Presupuesto principal (previsto vs real de la obra)
    env.DB.prepare(`SELECT presupuesto_previsto, presupuesto_real, coste_estimado
                    FROM obras WHERE id=? AND empresa_id=?`)
      .bind(obraId, empId).first(),
    // Fases de presupuesto
    env.DB.prepare(`SELECT nombre, presupuesto, coste_real, porcentaje_avance
                    FROM fases_obra WHERE obra_id=? AND empresa_id=? ORDER BY orden`)
      .bind(obraId, empId).all(),
    // Total costes reales acumulados
    env.DB.prepare(`SELECT COALESCE(SUM(importe),0) as total,
                           COALESCE(SUM(CASE WHEN estado='aprobado' THEN importe ELSE 0 END),0) as aprobado,
                           COALESCE(SUM(CASE WHEN estado='pendiente' THEN importe ELSE 0 END),0) as pendiente
                    FROM costes_obra WHERE obra_id=? AND empresa_id=?`)
      .bind(obraId, empId).first(),
    // Total contratos comprometidos
    env.DB.prepare(`SELECT COALESCE(SUM(importe_actual),0) as total,
                           COUNT(*) as num_contratos
                    FROM contratos_obra WHERE obra_id=? AND empresa_id=? AND estado NOT IN ('cancelado','borrador')`)
      .bind(obraId, empId).first(),
    // Costes por mes (historia completa para Curva S)
    env.DB.prepare(`SELECT strftime('%Y-%m', fecha) as mes,
                           COALESCE(SUM(importe),0) as total
                    FROM costes_obra WHERE obra_id=? AND empresa_id=?
                    GROUP BY mes ORDER BY mes`)
      .bind(obraId, empId).all(),
    // Costes por tipo/categor├Г┬нa
    env.DB.prepare(`SELECT COALESCE(tipo,'otro') as tipo,
                           COALESCE(SUM(importe),0) as total,
                           COUNT(*) as num
                    FROM costes_obra WHERE obra_id=? AND empresa_id=?
                    GROUP BY tipo ORDER BY total DESC`)
      .bind(obraId, empId).all(),
    // Contratos por tipo
    env.DB.prepare(`SELECT tipo, COALESCE(SUM(importe_actual),0) as total, COUNT(*) as num
                    FROM contratos_obra WHERE obra_id=? AND empresa_id=? AND estado NOT IN ('cancelado')
                    GROUP BY tipo ORDER BY total DESC`)
      .bind(obraId, empId).all(),
    // Hitos financieros (pagos/cobros pendientes)
    env.DB.prepare(`SELECT nombre, fecha_prevista, estado, descripcion
                    FROM hitos_obra WHERE obra_id=? AND empresa_id=? AND estado != 'completado'
                    ORDER BY fecha_prevista LIMIT 5`)
      .bind(obraId, empId).all(),
  ]);

  if (!obraR) return err('Obra no encontrada', 404);

  // ├втАЭтВм├втАЭтВм KPIs financieros ├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм├втАЭтВм
  const presupuesto  = obraR.presupuesto_previsto || 0;
  const presRealObra = obraR.presupuesto_real     || 0;
  const gastado      = costesR?.total             || 0;
  const comprometido = contratosTotR?.total        || 0;
  const avance       = (obraR.avance_porcentaje   || 0) / 100;

  // EAC (Estimate at Completion) = gastado / CPI si avance > 0
  const cpi        = avance > 0 && presupuesto > 0
    ? (avance * presupuesto) / (gastado || 1)
    : null;
  const eac        = cpi && cpi > 0 ? gastado / cpi : (gastado + comprometido);
  const variacion  = presupuesto > 0 ? presupuesto - eac : null;
  const ev         = Math.round(avance * presupuesto);
  // SPI тАФ approximation: PV_to_date based on elapsed % of project timeline
  let spi = null;
  if (avance > 0 && presupuesto > 0 && obraR.fecha_inicio && obraR.fecha_fin_prevista) {
    const ini   = new Date(obraR.fecha_inicio).getTime();
    const fin   = new Date(obraR.fecha_fin_prevista).getTime();
    const ahora = Date.now();
    if (fin > ini) {
      const pct_tiempo = Math.min(1, Math.max(0, (ahora - ini) / (fin - ini)));
      const pv_todate  = pct_tiempo * presupuesto;
      if (pv_todate > 0) spi = Math.round((ev / pv_todate) * 100) / 100;
    }
  }
  const pct_gastado  = presupuesto > 0 ? (gastado / presupuesto) * 100 : 0;
  const pct_comprometido = presupuesto > 0 ? (comprometido / presupuesto) * 100 : 0;

  return json({
    obra: {
      id: obraR.id,
      nombre: obraR.nombre,
      codigo: obraR.codigo,
      estado: obraR.estado,
      fecha_inicio: obraR.fecha_inicio,
      fecha_fin_prevista: obraR.fecha_fin_prevista,
      avance_porcentaje: obraR.avance_porcentaje || 0,
    },
    budget: {
      presupuesto_previsto: presupuesto,
      presupuesto_real: presRealObra,
      coste_estimado: obraR.coste_estimado || 0,
    },
    fases: fasesPR?.results || [],
    costes: {
      total: gastado,
      aprobado: costesR?.aprobado || 0,
      pendiente: costesR?.pendiente || 0,
    },
    contratos: {
      total: comprometido,
      num_contratos: contratosTotR?.num_contratos || 0,
    },
    por_mes: costesMesR?.results || [],
    por_tipo_coste: costestipoR?.results || [],
    por_tipo_contrato: contratosTipoR?.results || [],
    hitos_pendientes: (hitosR?.results) || [],
    kpis: {
      cpi: cpi ? Math.round(cpi * 100) / 100 : null,
      spi: spi,
      ev: ev,
      eac: Math.round(eac),
      variacion: variacion !== null ? Math.round(variacion) : null,
      pct_gastado: Math.round(pct_gastado * 10) / 10,
      pct_comprometido: Math.round(pct_comprometido * 10) / 10,
      alerta: eac > presupuesto * 1.05 ? 'rojo'
             : eac > presupuesto * 1.02 ? 'amarillo'
             : 'verde',
    },
  });
}

// ├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р
//  NEW-52 ├втВмтАЭ CRONOGRAMA / GANTT DE OBRA
// ├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р├втАв┬Р
async function getCronogramaObra(obraId, request, env) {
  const auth = await getAuth(request, env);
  if (!auth?.empresa_id) return err('No autorizado', 403);
  const eid = auth.empresa_id;

  const [obraR, fasesR, hitosR, tareasR] = await Promise.all([
    env.DB.prepare(
      `SELECT id, nombre, codigo, fecha_inicio, fecha_fin_prevista, avance_porcentaje, estado, cliente
       FROM obras WHERE id=? AND empresa_id=?`
    ).bind(obraId, eid).first(),
    env.DB.prepare(
      `SELECT id, nombre, descripcion, fecha_inicio_plan, fecha_fin_plan,
              fecha_inicio_real, fecha_fin_real, porcentaje, estado, responsable, orden
       FROM fases_obra WHERE obra_id=? AND empresa_id=? ORDER BY orden ASC, id ASC`
    ).bind(obraId, eid).all(),
    env.DB.prepare(
      `SELECT id, nombre, fecha, estado, tipo, responsable, notas
       FROM hitos_obra WHERE obra_id=? AND empresa_id=? ORDER BY fecha ASC`
    ).bind(obraId, eid).all(),
    env.DB.prepare(
      `SELECT id, titulo, estado, prioridad, fase_id, fecha_limite, asignado_a
       FROM tareas_obra WHERE obra_id=? AND empresa_id=? ORDER BY fase_id ASC, id ASC`
    ).bind(obraId, eid).all(),
  ]);

  if (!obraR) return err('Obra no encontrada', 404);

  const fases  = fasesR?.results  || [];
  const hitos  = hitosR?.results  || [];
  const tareas = tareasR?.results || [];

  // Calcular rango de fechas total (para el eje X del Gantt)
  const toMs = s => s ? new Date(s).getTime() : null;
  const allDates = [
    ...fases.map(f => [toMs(f.fecha_inicio_plan), toMs(f.fecha_fin_plan)]).flat(),
    ...hitos.map(h => toMs(h.fecha)),
    toMs(obraR.fecha_inicio), toMs(obraR.fecha_fin_prevista),
  ].filter(Boolean);
  const rangeStart = allDates.length ? Math.min(...allDates) : Date.now();
  const rangeEnd   = allDates.length ? Math.max(...allDates) : Date.now() + 30*24*3600*1000;

  // Estad├Г┬нsticas
  const totalFases    = fases.length;
  const fasesOk       = fases.filter(f => f.estado === 'completada').length;
  const fasesEnCurso  = fases.filter(f => f.estado === 'en_curso').length;
  const hitosOk       = hitos.filter(h => h.estado === 'completado').length;
  const hitosVencidos = hitos.filter(h => {
    const hoy = new Date().toISOString().slice(0,10);
    return h.estado !== 'completado' && h.fecha && h.fecha < hoy;
  }).length;
  const tareasOk  = tareas.filter(t => t.estado === 'completada').length;
  const tareasTotal = tareas.length;

  return json({
    obra: obraR,
    fases,
    hitos,
    tareas,
    rango: {
      inicio: new Date(rangeStart).toISOString().slice(0,10),
      fin:    new Date(rangeEnd).toISOString().slice(0,10),
    },
    stats: {
      total_fases: totalFases, fases_ok: fasesOk, fases_en_curso: fasesEnCurso,
      total_hitos: hitos.length, hitos_ok: hitosOk, hitos_vencidos: hitosVencidos,
      total_tareas: tareasTotal, tareas_ok: tareasOk,
    },
  });
}


